// typeBadgeStyle returns inline CSS for a type badge based on workflow color.
func typeBadgeStyle(typeName string, workflows []core.WorkflowDef) string {
	for _, wf := range workflows {
		if wf.TaskType == typeName && wf.Color != "" {
			return fmt.Sprintf("background:%s;color:%s;", wf.Color, typeBadgeFg(wf.TaskType))
		}
	}
	// Fallback for built-in types (when workflows not loaded yet)
	switch typeName {
	case "bug":
		return "background:#fde8ee;color:var(--klt-danger);"
	case "feature":
		return "background:#f0e8ff;color:var(--klt-purple);"
	case "hotfix":
		return "background:#fff1e6;color:var(--klt-orange);"
	default:
		return "background:var(--klt-accent-light);color:var(--klt-accent);"
	}
}

// typeBadgeFg returns the foreground color for a type badge.
func typeBadgeFg(typeName string) string {
	switch typeName {
	case "task":
		return "var(--klt-accent)"
	case "bug":
		return "var(--klt-danger)"
	case "feature":
		return "var(--klt-purple)"
	case "hotfix":
		return "var(--klt-orange)"
	default:
		return "var(--klt-fg)"
	}
}

// capitalize returns the string with the first letter uppercased.
func capitalize(s string) string {
	if s == "" {
		return s
	}
	return strings.ToUpper(s[:1]) + s[1:]
}

